// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package policy

import (
	"context"
	"log/slog"
	"time"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/lock"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

// PolicyAuditLogger provides structured logging of policy evaluation decisions for audit and debugging purposes.
type PolicyAuditLogger struct {
	lock.Mutex
	logger   *slog.Logger
	logLevel slog.Level
}

// NewPolicyAuditLogger creates a new PolicyAuditLogger with the specified logger and log level.
// If logger is nil, a default logger will be used.
func NewPolicyAuditLogger(logger *slog.Logger, level slog.Level) *PolicyAuditLogger {
	if logger == nil {
		logger = slog.Default()
	}
	return &PolicyAuditLogger{
		logger:   logger,
		logLevel: level,
	}
}

// LogDecision logs a policy evaluation decision with identity, policy, verdict, and reason.
// This method is thread-safe and structured for audit purposes.
func (pal *PolicyAuditLogger) LogDecision(identity identity.NumericIdentity, policy string, verdict string, reason string) {
	pal.Lock()
	defer pal.Unlock()

	if pal.logger == nil {
		return
	}

	pal.logger.LogAttrs(context.Background(), pal.logLevel,
		"policy decision",
		slog.String(logfields.Identity, identity.String()),
		slog.String("policy", policy),
		slog.String("verdict", verdict),
		slog.String("reason", reason),
		slog.Int64("timestamp", time.Now().UnixNano()),
	)
}

// LogEvaluation logs a policy evaluation result with context, policy key, selector cache, and result.
// This method is thread-safe and provides detailed evaluation information for debugging.
func (pal *PolicyAuditLogger) LogEvaluation(ctx context.Context, policyKey string, selectorCache *SelectorCache, result interface{}) {
	pal.Lock()
	defer pal.Unlock()

	if pal.logger == nil {
		return
	}

	attrs := []slog.Attr{
		slog.String(logfields.PolicyKey, policyKey),
		slog.Any("result", result),
		slog.Int64("timestamp", time.Now().UnixNano()),
	}

	// If selectorCache is available, log its revision
	if selectorCache != nil {
		attrs = append(attrs, slog.Uint64("selector_revision", uint64(selectorCache.Revision())))
	}

	pal.logger.LogAttrs(ctx, pal.logLevel,
		"policy evaluation",
		attrs...,
	)
}

// SetLogLevel updates the log level for this audit logger.
// This method is thread-safe.
func (pal *PolicyAuditLogger) SetLogLevel(level slog.Level) {
	pal.Lock()
	defer pal.Unlock()
	pal.logLevel = level
}

// GetLogLevel returns the current log level of this audit logger.
// This method is thread-safe.
func (pal *PolicyAuditLogger) GetLogLevel() slog.Level {
	pal.Lock()
	defer pal.Unlock()
	return pal.logLevel
}

